mapper.select:
SELECT RPT_GJDT AS CODE, DATE_FORMAT(DATE_FORMAT(RPT_GJDT,'%Y%m%d'), '%Y-%m-%d') AS NAME FROM JRBA_RPT_BAS_M WHERE 1=1
AND RPT_GJDT != #{filterComboVal,jdbcType=VARCHAR}
GROUP BY RPT_GJDT ORDER BY RPT_GJDT DESC

SELECT COUNT(*) AS CNT 
FROM JRBA_RPT_BAS_M A    
WHERE A.RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR}

