   SET BT_BAS_DT = #{DATA_BAS_DT, jdbcType=VARCHAR} 
 WHERE RPT_GJDT=#{RPT_GJDT, jdbcType=VARCHAR}

UPDATE JRBA_JIPYO_M SET
	MNG_BRNO 		= #{MNG_BRNO,jdbcType=VARCHAR}
WHERE RPT_GJDT 		= #{RPT_GJDT, jdbcType=VARCHAR}
	AND JIPYO_IDX 		= #{JIPYO_IDX, jdbcType=VARCHAR}

