SET JIPYO_FIX_YN= 1,
	JIPYO_FIX_DT = DATE_FORMAT(SYSDATE(),'%Y%m%d'),
	JIPYO_FIX_JKW_NO = #{CHG_OP_JKW_NO}
WHERE RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR}

UPDATE JRBA_RPT_BAS_M
