	JIPYO_FIX_JKW_NO = #{CHG_OP_JKW_NO}
WHERE RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR}

mapper.delete:
DELETE FROM JRBA_JIPYO_M
WHERE RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR}
	AND JIPYO_IDX = #{JIPYO_IDX, jdbcType=VARCHAR}

mapper.select:
SELECT JIPYO_IDX
FROM JRBA_JIPYO_V
WHERE RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR}
	AND JIPYO_IDX = #{JIPYO_IDX, jdbcType=VARCHAR}

SELECT A.JIPYO_IDX -- 지표번호 ,A.JIPYO_NM -- 위험지표명 ,A.INP_ITEM -- 입력항목 ,A.VALT_G -- 평가구분코드 HIDDEN ,(SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A007' AND DTL_CD=A.VALT_G) AS VALT_G_NM -- 평가구분명 ,A.INP_UNIT_C -- 입력단위코드 HIDDEN ,(SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A012' AND DTL_CD=A.INP_UNIT_C) AS INP_UNIT_C_NM -- 입력단위명 ,A.ALLT_PNT -- 배점 ,A.IN_V_TP_C -- 입력값타입('A008', N:숫자, C:코드, T:텍스트) ,B.IN_V -- 입력값 ,(CASE WHEN A.JIPYO_C = 'I' THEN '' WHEN A.JIPYO_C = 'O' AND A.VALT_G IN ('1', '4') AND B.IN_V IS NOT NULL THEN TRIM(TRAILING '.' FROM TRIM(FORMAT(B.RPT_PNT, 2))) WHEN A.JIPYO_C = 'O' AND A.VALT_G ='2' AND B.MAX_IN_V > 0 THEN TRIM(TRAILING '.' FROM TRIM(FORMAT(B.RPT_PNT, 2))) ELSE '' END ) AS RPT_PNT -- 지표점수 ,CASE WHEN IFNULL(B.ATTCH_FILE_NO, 0) = 0 THEN 'N' ELSE 'Y' END AS ATTCH_FILE_YN -- 증빙파일 ,B.ATTCH_FILE_NO -- 첨부파일번호 ,IFNULL(B.ITEM_S_C, '0') AS ITEM_S_C -- 항목상태 HIDDEN ('A010', 0:미확정, 1:저장, 2:확정) ,(SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A010' AND DTL_CD=IFNULL(B.ITEM_S_C,0)) AS ITEM_S_C_NM -- 항목상태명 ,A.CAL_FRML -- 산출식 ,A.CAL_METH -- 산출방법 ,A.JIPYO_C -- 위험구분코드 HIDDEN ,(SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A001' AND DTL_CD=A.JIPYO_C) AS JIPYO_C_NM -- 위험구분코드명 ,A.RSK_CATG -- 카테고리코드 HIDDEN ,CASE WHEN A.JIPYO_C='I' THEN (SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A004' AND DTL_CD=A.RSK_CATG) -- 고유위험인 경우 WHEN A.JIPYO_C='O' THEN (SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A002' AND DTL_CD=A.RSK_CATG) -- 운영위험인 경우 END AS RSK_CATG_NM -- 위험구분코드명 ,A.RSK_FAC -- 항목코드 HIDDEN ,CASE WHEN A.JIPYO_C='I' THEN (SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A005' AND DTL_CD=A.RSK_FAC) -- 고유위험인 경우 WHEN A.JIPYO_C='O' THEN (SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A003' AND DTL_CD=A.RSK_FAC) -- 운영위험인 경우 END AS RSK_FAC_NM -- 위험구분코드명 ,A.CHG_DT -- 변경일 ,A.CHG_OP_JKW_NO -- 변경자 ,CASE WHEN IN_V_TP_C='C' -- 입력값이 '코드' THEN ( SELECT REGEXP_REPLACE(CONCAT(GROUP_CONCAT(DTL_CD, '##'), '@@', GROUP_CONCAT(CONCAT('[' , DTL_CD , '] ' , DTL_NM), '##')) ,'([^,]+)(,\1)+','\1' ) FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD=A.CNCT_JIPYO_C_I GROUP BY RPT_GJDT, GRP_CD ORDER BY DTL_CD ) END AS CD_LST -- 입력값타입이 코드인경우 사용될 코드리스트 ,IFNULL(B.MAX_IN_V,0) AS MAX_IN_V ,A.CNCT_JIPYO_C_I -- 연결지표코드정보 ,IFNULL(CASE WHEN IN_V_TP_C='C' -- 입력값이 '코드' THEN ( SELECT CONCAT('[',DTL_CD,'] ',DTL_NM) FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD=A.CNCT_JIPYO_C_I AND DTL_CD=(SELECT IN_V FROM JRBA_JIPYO_V WHERE JIPYO_IDX=A.JIPYO_IDX AND RPT_GJDT=#{LAST_RPT_GJDT, jdbcType=VARCHAR}) ) ELSE ( SELECT IN_V FROM JRBA_JIPYO_V WHERE JIPYO_IDX=A.JIPYO_IDX AND RPT_GJDT=#{LAST_RPT_GJDT, jdbcType=VARCHAR} ) END, '-') AS LAST_IN_V -- 직전기준보고일 데이터 ,( CASE TRIM(B.BIGO_CTNT) WHEN '' THEN 'N' ELSE 'Y' END) AS BIGO_CTNT_F -- 비고내용 저장여부 ,B.BIGO_CTNT -- 비고내용 FROM JRBA_JIPYO_M A LEFT OUTER JOIN JRBA_JIPYO_V B ON A.RPT_GJDT = B.RPT_GJDT AND A.JIPYO_IDX = B.JIPYO_IDX WHERE A.JIPYO_USYN = '1' --지표사용여부 (0:부, 1:여) AND A.RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR}
AND A.JIPYO_IDX = #{CHECK_JIPYO_IDX, jdbcType=VARCHAR} -- 지표번호
AND A.JIPYO_IDX LIKE CONCAT('%' , #{JIPYO_IDX, jdbcType=VARCHAR} , '%') -- 지표번호
AND A.JIPYO_NM LIKE CONCAT('%' , #{JIPYO_NM, jdbcType=VARCHAR} , '%') -- 지표명
AND A.JIPYO_C = #{JIPYO_C, jdbcType=VARCHAR}
AND A.RSK_CATG = #{RSK_CATG, jdbcType=VARCHAR}
AND A.RSK_FAC = #{RSK_FAC, jdbcType=VARCHAR}
AND A.VALT_G = #{VALT_G, jdbcType=VARCHAR}
AND A.JIPYO_IDX NOT IN (SELECT JIPYO_IDX FROM JRBA_JIPYO_V WHERE RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR})
AND B.ITEM_S_C = #{ITEM_S_C, jdbcType=VARCHAR}
AND A.MNG_BRNO = #{MNG_BRNO, jdbcType=VARCHAR}
AND A.IN_METH_C = #{IN_METH_C, jdbcType=VARCHAR} -- 입력방식
ORDER BY A.JIPYO_IDX

SELECT A.JIPYO_IDX -- 지표번호 ,A.JIPYO_NM -- 위험지표명 ,A.INP_ITEM -- 입력항목 ,A.VALT_G -- 평가구분코드 HIDDEN ,(SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A007' AND DTL_CD=A.VALT_G) AS VALT_G_NM -- 평가구분명 ,A.INP_UNIT_C -- 입력단위코드 HIDDEN ,(SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A012' AND DTL_CD=A.INP_UNIT_C) AS INP_UNIT_C_NM -- 입력단위명 ,A.ALLT_PNT -- 배점 ,A.IN_V_TP_C -- 입력값타입('A008', N:숫자, C:코드, T:텍스트) ,B.IN_V ,IFNULL(CASE WHEN IN_V_TP_C='C' -- 입력값이 '코드' THEN ( SELECT CONCAT('[',DTL_CD,'] ',DTL_NM) FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD=A.CNCT_JIPYO_C_I AND DTL_CD=B.IN_V ) ELSE FORMAT(B.IN_V,0) END, '-') AS A_IN_V -- 입력값 ,(CASE WHEN A.JIPYO_C = 'I' THEN '' WHEN A.JIPYO_C = 'O' AND A.VALT_G IN ('1', '4') AND B.IN_V IS NOT NULL THEN TRIM(TRAILING '.' FROM TRIM(FORMAT(B.RPT_PNT, 2))) WHEN A.JIPYO_C = 'O' AND A.VALT_G ='2' AND B.MAX_IN_V > 0 THEN TRIM(TRAILING '.' FROM TRIM(FORMAT(B.RPT_PNT, 2))) ELSE '' END ) AS RPT_PNT -- 지표점수 ,CASE WHEN IFNULL(B.ATTCH_FILE_NO, 0) = 0 THEN 'N' ELSE 'Y' END AS ATTCH_FILE_YN -- 증빙파일 ,B.ATTCH_FILE_NO -- 첨부파일번호 ,IFNULL(B.ITEM_S_C, '0') AS ITEM_S_C -- 항목상태 HIDDEN ('A010', 0:미확정, 1:저장, 2:확정) ,(SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A010' AND DTL_CD=IFNULL(B.ITEM_S_C,0)) AS ITEM_S_C_NM -- 항목상태명 ,A.CAL_FRML -- 산출식 ,A.CAL_METH -- 산출방법 ,A.JIPYO_C -- 위험구분코드 HIDDEN ,(SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A001' AND DTL_CD=A.JIPYO_C) AS JIPYO_C_NM -- 위험구분코드명 ,A.RSK_CATG -- 카테고리코드 HIDDEN ,CASE WHEN A.JIPYO_C='I' THEN (SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A004' AND DTL_CD=A.RSK_CATG) -- 고유위험인 경우 WHEN A.JIPYO_C='O' THEN (SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A002' AND DTL_CD=A.RSK_CATG) -- 운영위험인 경우 END AS RSK_CATG_NM -- 위험구분코드명 ,A.RSK_FAC -- 항목코드 HIDDEN ,CASE WHEN A.JIPYO_C='I' THEN (SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A005' AND DTL_CD=A.RSK_FAC) -- 고유위험인 경우 WHEN A.JIPYO_C='O' THEN (SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A003' AND DTL_CD=A.RSK_FAC) -- 운영위험인 경우 END AS RSK_FAC_NM -- 위험구분코드명 ,A.CHG_DT -- 변경일 ,A.CHG_OP_JKW_NO -- 변경자 ,CASE WHEN IN_V_TP_C='C' -- 입력값이 '코드' THEN ( SELECT REGEXP_REPLACE(CONCAT(GROUP_CONCAT(DTL_CD, '##'), '@@', GROUP_CONCAT(CONCAT('[' , DTL_CD , '] ' , DTL_NM), '##')) ,'([^,]+)(,\1)+','\1' ) FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD=A.CNCT_JIPYO_C_I GROUP BY RPT_GJDT, GRP_CD ORDER BY DTL_CD ) END AS CD_LST -- 입력값타입이 코드인경우 사용될 코드리스트 ,IFNULL(B.MAX_IN_V,0) AS MAX_IN_V ,A.CNCT_JIPYO_C_I -- 연결지표코드정보 ,IFNULL(CASE WHEN IN_V_TP_C='C' -- 입력값이 '코드' THEN ( SELECT CONCAT('[',DTL_CD,'] ',DTL_NM) FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD=A.CNCT_JIPYO_C_I AND DTL_CD=(SELECT IN_V FROM JRBA_JIPYO_V WHERE JIPYO_IDX=A.JIPYO_IDX AND RPT_GJDT=#{LAST_RPT_GJDT, jdbcType=VARCHAR}) ) ELSE ( SELECT IN_V FROM JRBA_JIPYO_V WHERE JIPYO_IDX=A.JIPYO_IDX AND RPT_GJDT=#{LAST_RPT_GJDT, jdbcType=VARCHAR} ) END, '-') AS LAST_IN_V -- 직전기준보고일 데이터 ,( CASE TRIM(B.BIGO_CTNT) WHEN '' THEN 'N' ELSE 'Y' END) AS BIGO_CTNT_F -- 비고내용 저장여부 ,B.BIGO_CTNT -- 비고내용 FROM JRBA_JIPYO_M A LEFT OUTER JOIN JRBA_JIPYO_V B ON A.RPT_GJDT = B.RPT_GJDT AND A.JIPYO_IDX = B.JIPYO_IDX WHERE A.JIPYO_USYN = '1' --지표사용여부 (0:부, 1:여) AND A.RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR}
AND A.JIPYO_IDX = #{CHECK_JIPYO_IDX, jdbcType=VARCHAR} -- 지표번호
AND A.JIPYO_IDX LIKE CONCAT('%' , #{JIPYO_IDX, jdbcType=VARCHAR} , '%') -- 지표번호
AND A.JIPYO_NM LIKE CONCAT('%' , #{JIPYO_NM, jdbcType=VARCHAR} , '%') -- 지표명
AND A.JIPYO_C = #{JIPYO_C, jdbcType=VARCHAR}
AND A.RSK_CATG = #{RSK_CATG, jdbcType=VARCHAR}
AND A.RSK_FAC = #{RSK_FAC, jdbcType=VARCHAR}
AND A.VALT_G = #{VALT_G, jdbcType=VARCHAR}
AND A.JIPYO_IDX NOT IN (SELECT JIPYO_IDX FROM JRBA_JIPYO_V WHERE RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR})
AND B.ITEM_S_C = #{ITEM_S_C, jdbcType=VARCHAR}
AND A.MNG_BRNO = #{MNG_BRNO, jdbcType=VARCHAR}
AND A.IN_METH_C = #{IN_METH_C, jdbcType=VARCHAR} -- 입력방식
ORDER BY A.JIPYO_IDX

