UPDATE JRBA_RPT_BAS_M SET
	BT_JOB_ENDT = DATE_FORMAT(SYSDATE(),'%Y%m%d')
WHERE RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR}

           INSERT INTO JRBA_JIPYO_V 
	    (
	    RPT_GJDT
	    ,JIPYO_IDX
	    ,IN_V
	    ,RPT_PNT
	    ,ITEM_S_C
	    ,DR_DT
	    ,DR_TIME
	    ,DR_OP_JKW_NO
	    ,CHG_DT
	    ,CHG_TIME
	    ,CHG_OP_JKW_NO
	    )
	VALUES
	    (
	    #{RPT_GJDT, jdbcType=VARCHAR}
	    ,#{JIPYO_IDX, jdbcType=VARCHAR}
	    ,#{IN_V, jdbcType=VARCHAR}
	    ,#{RPT_PNT, jdbcType=VARCHAR}
	    ,#{ITEM_S_C, jdbcType=VARCHAR}
	    ,DATE_FORMAT(SYSDATE(),'%Y%m%d')
	    ,DATE_FORMAT(SYSDATE(),'%H%i%s')
	    ,#{DR_OP_JKW_NO, jdbcType=VARCHAR}
	    ,DATE_FORMAT(SYSDATE(),'%Y%m%d')
	    ,DATE_FORMAT(SYSDATE(),'%H%i%s')
	    ,#{DR_OP_JKW_NO, jdbcType=VARCHAR}
	    )
            ON DUPLICATE KEY 
            UPDATE
	       IN_V 	 		= #{IN_V, jdbcType=VARCHAR}
           ,RPT_PNT  		= #{RPT_PNT, jdbcType=VARCHAR}
           ,ITEM_S_C 		= #{ITEM_S_C, jdbcType=VARCHAR}
           ,CHG_DT 	 		= DATE_FORMAT(SYSDATE(),'%Y%m%d')
           ,CHG_TIME 		= DATE_FORMAT(SYSDATE(),'%H%i%s')
           ,CHG_OP_JKW_NO 	= #{DR_OP_JKW_NO, jdbcType=VARCHAR}

           INSERT INTO JRBA_FIU_JIPYO_V 
	    (
	    RPT_GJDT
	    ,JIPYO_IDX
	    ,IN_V
	    ,RPT_PNT
	    ,ITEM_S_C
	    ,DR_DT
	    ,DR_TIME
	    ,DR_OP_JKW_NO
	    ,CHG_DT
	    ,CHG_TIME
	    ,CHG_OP_JKW_NO
	    )
	VALUES
	    (
	    #{RPT_GJDT, jdbcType=VARCHAR}
	    ,#{JIPYO_IDX, jdbcType=VARCHAR}
	    ,#{IN_V, jdbcType=VARCHAR}
	    ,#{RPT_PNT, jdbcType=VARCHAR}
	    ,#{ITEM_S_C, jdbcType=VARCHAR}
	    ,DATE_FORMAT(SYSDATE(),'%Y%m%d')
	    ,DATE_FORMAT(SYSDATE(),'%H%i%s')
	    ,#{DR_OP_JKW_NO, jdbcType=VARCHAR}
	    ,DATE_FORMAT(SYSDATE(),'%Y%m%d')
	    ,DATE_FORMAT(SYSDATE(),'%H%i%s')
	    ,#{DR_OP_JKW_NO, jdbcType=VARCHAR}
	    )
            ON DUPLICATE KEY 
            UPDATE
	       IN_V 	 		= #{IN_V, jdbcType=VARCHAR}
           ,RPT_PNT  		= #{RPT_PNT, jdbcType=VARCHAR}
           ,ITEM_S_C 		= #{ITEM_S_C, jdbcType=VARCHAR}
           ,CHG_DT 	 		= DATE_FORMAT(SYSDATE(),'%Y%m%d')
           ,CHG_TIME 		= DATE_FORMAT(SYSDATE(),'%H%i%s')
           ,CHG_OP_JKW_NO 	= #{DR_OP_JKW_NO, jdbcType=VARCHAR}

UPDATE JRBA_JIPYO_V
   SET ITEM_S_C 		= #{ITEM_S_C, jdbcType=VARCHAR}
       ,CHG_DT 			= DATE_FORMAT(SYSDATE(),'%Y%m%d')
       ,CHG_TIME 		= DATE_FORMAT(SYSDATE(),'%H%i%s')
       ,CHG_OP_JKW_NO 	= #{DR_OP_JKW_NO, jdbcType=VARCHAR}
 WHERE RPT_GJDT 		= #{RPT_GJDT, jdbcType=VARCHAR}
   AND JIPYO_IDX 		= #{JIPYO_IDX, jdbcType=VARCHAR}

UPDATE JRBA_FIU_JIPYO_V
   SET ITEM_S_C 		= #{ITEM_S_C, jdbcType=VARCHAR}
       ,CHG_DT 			= DATE_FORMAT(SYSDATE(),'%Y%m%d')
       ,CHG_TIME 		= DATE_FORMAT(SYSDATE(),'%H%i%s')
       ,CHG_OP_JKW_NO 	= #{DR_OP_JKW_NO, jdbcType=VARCHAR}
 WHERE RPT_GJDT 		= #{RPT_GJDT, jdbcType=VARCHAR}
   AND JIPYO_IDX 		= #{JIPYO_IDX, jdbcType=VARCHAR}

mapper.select:
SELECT IFNULL(MAX(RPT_GJDT),0) AS LAST_RPT_GJDT
  FROM JRBA_RPT_BAS_M
 WHERE RPT_GJDT  != #{RPT_GJDT, jdbcType=VARCHAR}
   AND RPT_GJDT < #{RPT_GJDT, jdbcType=VARCHAR}
 ORDER BY RPT_GJDT DESC

SELECT IN_V
       ,MAX_IN_V
       ,ATTCH_FILE_NO
  FROM JRBA_JIPYO_V
 WHERE RPT_GJDT = #{LAST_RPT_GJDT, jdbcType=VARCHAR}
   AND JIPYO_IDX = #{JIPYO_IDX, jdbcType=VARCHAR}

