mapper.select:
SELECT A.JIPYO_IDX , A.RPT_GJDT, A.JIPYO_IDX, A.JIPYO_C, CD01.DTL_NM AS JIPYO_C_NM , A.RSK_CATG, (CASE WHEN A.JIPYO_C='O' THEN CD02.DTL_NM ELSE CD04.DTL_NM END) AS RSK_CATG_NM , A.RSK_FAC, (CASE WHEN A.JIPYO_C='O' THEN CD03.DTL_NM ELSE CD05.DTL_NM END) AS RSK_FAC_NM , A.JIPYO_NM ,(SELECT CONVERT(RPT_PNT, DECIMAL(4,2)) FROM JRBA_FIU_JIPYO_V WHERE RPT_GJDT=B.RPT_GJDT1 AND JIPYO_IDX =A.JIPYO_IDX) AS SCORE1 ,(SELECT CONVERT(RPT_PNT, DECIMAL(4,2)) FROM JRBA_FIU_JIPYO_V WHERE RPT_GJDT=B.RPT_GJDT2 AND JIPYO_IDX =A.JIPYO_IDX) AS SCORE2 ,(SELECT CONVERT(RPT_PNT, DECIMAL(4,2)) FROM JRBA_FIU_JIPYO_V WHERE RPT_GJDT=B.RPT_GJDT3 AND JIPYO_IDX =A.JIPYO_IDX) AS SCORE3 , IFNULL((SELECT IN_V FROM JRBA_FIU_JIPYO_V WHERE RPT_GJDT=B.RPT_GJDT1 AND JIPYO_IDX=A.JIPYO_IDX ),0) AS VAL1 , IFNULL((SELECT IN_V FROM JRBA_FIU_JIPYO_V WHERE RPT_GJDT=B.RPT_GJDT2 AND JIPYO_IDX=A.JIPYO_IDX ),0) AS VAL2 , IFNULL((SELECT IN_V FROM JRBA_FIU_JIPYO_V WHERE RPT_GJDT=B.RPT_GJDT3 AND JIPYO_IDX=A.JIPYO_IDX ),0) AS VAL3 ,(CASE WHEN A.JIPYO_C = 'I' THEN '' WHEN A.JIPYO_C = 'O' THEN (SELECT FORMAT(V_SCORE_DIFFERENCE1.SCOREDR, 2) FROM ( SELECT V.JIPYO_IDX , V.RPT_GJDT , CONVERT(V.RPT_PNT, DECIMAL(4,2)) - (SELECT CONVERT(RPT_PNT, DECIMAL(4,2)) FROM JRBA_FIU_JIPYO_V X WHERE X.RPT_GJDT =VG.RPT_GJDT2 AND X.JIPYO_IDX =V.JIPYO_IDX ) AS SCOREDR FROM JRBA_FIU_JIPYO_V V , ( SELECT MAX(CASE B.SNO WHEN 1 THEN B.RPT_GJDT ELSE '' END ) AS RPT_GJDT1 , MAX(CASE B.SNO WHEN 2 THEN B.RPT_GJDT ELSE '' END ) AS RPT_GJDT2 , MAX(CASE B.SNO WHEN 3 THEN B.RPT_GJDT ELSE '' END ) AS RPT_GJDT3 FROM ( SELECT A.RPT_GJDT , (@ROWNUM := @ROWNUM + 1) SNO FROM ( SELECT RPT_GJDT FROM JRBA_RPT_BAS_M WHERE RPT_GJDT <= #{RPT_GJDT,jdbcType=VARCHAR} ORDER BY RPT_GJDT DESC ) A, (SELECT @ROWNUM := 0) R LIMIT 0,3 ) B ) VG WHERE V.RPT_GJDT = VG.RPT_GJDT1 ) V_SCORE_DIFFERENCE1 WHERE V_SCORE_DIFFERENCE1.JIPYO_IDX = A.JIPYO_IDX ) ELSE '' END ) AS SCOREDR1 -- (최근회차 - 직전회차) ,(CASE WHEN A.JIPYO_C = 'I' THEN '' WHEN A.JIPYO_C = 'O' THEN ( SELECT FORMAT(V_SCORE_DIFFERENCE2.SCOREDR, 2) FROM ( SELECT V.JIPYO_IDX , V.RPT_GJDT , CONVERT(V.RPT_PNT, DECIMAL(4,2)) - (SELECT CONVERT(RPT_PNT, DECIMAL(4,2)) FROM JRBA_FIU_JIPYO_V X WHERE X.RPT_GJDT =VG.RPT_GJDT3 AND X.JIPYO_IDX =V.JIPYO_IDX ) AS SCOREDR FROM JRBA_FIU_JIPYO_V V , ( SELECT MAX(CASE B.SNO WHEN 1 THEN B.RPT_GJDT ELSE '' END ) AS RPT_GJDT1 , MAX(CASE B.SNO WHEN 2 THEN B.RPT_GJDT ELSE '' END ) AS RPT_GJDT2 , MAX(CASE B.SNO WHEN 3 THEN B.RPT_GJDT ELSE '' END ) AS RPT_GJDT3 FROM ( SELECT A.RPT_GJDT , (@ROWNUM := @ROWNUM + 1) SNO FROM ( SELECT RPT_GJDT FROM JRBA_RPT_BAS_M WHERE RPT_GJDT <= #{RPT_GJDT,jdbcType=VARCHAR} ORDER BY RPT_GJDT DESC ) A, (SELECT @ROWNUM := 0) R LIMIT 0,3 ) B ) VG WHERE V.RPT_GJDT = VG.RPT_GJDT2 )V_SCORE_DIFFERENCE2 WHERE V_SCORE_DIFFERENCE2.JIPYO_IDX = A.JIPYO_IDX ) ELSE '' END ) AS SCOREDR2 -- (직전회차 - 전전회차) , A.RPT_GJDT , B.RPT_GJDT1 , B.RPT_GJDT2 , B.RPT_GJDT3 , IFNULL(D.GYLJ_ID, 0) AS GYLJ_ID -- 결재ID , IFNULL(D.GYLJ_S_C, 0) AS GYLJ_S_C -- 결재상태코드 , CASE WHEN IFNULL(D.GYLJ_S_C, 0) = '3' THEN 'Y' -- 지표결재상태코드(A014) = 3(완료) ELSE 'N' END FINL_GYLJ_S -- 최종승인여부 FROM JRBA_FIU_JIPYO_V C INNER JOIN JRBA_JIPYO_M A ON (A.RPT_GJDT=C.RPT_GJDT AND A.JIPYO_IDX = C.JIPYO_IDX ) LEFT JOIN JRBA_DTL_C CD01 ON A.RPT_GJDT=CD01.RPT_GJDT AND CD01.GRP_CD = 'A001' AND A.JIPYO_C=CD01.DTL_CD LEFT JOIN JRBA_DTL_C CD02 ON A.RPT_GJDT=CD02.RPT_GJDT AND CD02.GRP_CD = 'A002' AND A.RSK_CATG=CD02.DTL_CD LEFT JOIN JRBA_DTL_C CD03 ON A.RPT_GJDT=CD03.RPT_GJDT AND CD03.GRP_CD = 'A003' AND A.RSK_FAC=CD03.DTL_CD LEFT JOIN JRBA_DTL_C CD04 ON A.RPT_GJDT=CD04.RPT_GJDT AND CD04.GRP_CD = 'A004' AND A.RSK_CATG=CD04.DTL_CD LEFT JOIN JRBA_DTL_C CD05 ON A.RPT_GJDT=CD05.RPT_GJDT AND CD05.GRP_CD = 'A005' AND A.RSK_FAC=CD05.DTL_CD LEFT JOIN JRBA_DTL_C CD06 ON A.RPT_GJDT=CD06.RPT_GJDT AND CD06.GRP_CD = 'A007' AND A.VALT_G=CD06.DTL_CD LEFT JOIN JRBA_DTL_C CD07 ON A.RPT_GJDT=CD07.RPT_GJDT AND CD07.GRP_CD = 'A013' AND A.IN_METH_C=CD07.DTL_CD LEFT JOIN JRBA_RPT_RST_M D ON A.RPT_GJDT = D.RPT_GJDT -- 보고기준일자 , ( SELECT MAX(CASE B.SNO WHEN 1 THEN B.RPT_GJDT ELSE '' END ) AS RPT_GJDT1 , MAX(CASE B.SNO WHEN 2 THEN B.RPT_GJDT ELSE '' END ) AS RPT_GJDT2 , MAX(CASE B.SNO WHEN 3 THEN B.RPT_GJDT ELSE '' END ) AS RPT_GJDT3 FROM ( SELECT A.RPT_GJDT , (@ROWNUM := @ROWNUM + 1) SNO FROM ( SELECT RPT_GJDT FROM JRBA_RPT_BAS_M WHERE RPT_GJDT <= #{RPT_GJDT,jdbcType=VARCHAR} ORDER BY RPT_GJDT DESC ) A, (SELECT @ROWNUM := 0) R LIMIT 0,3 ) B ) B WHERE 1=1 AND A.RPT_GJDT = B.RPT_GJDT1
AND A.JIPYO_IDX LIKE CONCAT('%' , #{JIPYO_IDX, jdbcType=VARCHAR} , '%' )
AND A.JIPYO_NM LIKE CONCAT('%' , #{JIPYO_NM, jdbcType=VARCHAR} , '%')
AND A.JIPYO_C = #{JIPYO_C,jdbcType=VARCHAR}
AND A.RSK_CATG = #{RSK_CATG,jdbcType=VARCHAR}
AND A.RSK_FAC = #{RSK_FAC,jdbcType=VARCHAR}
ORDER BY A.JIPYO_IDX ASC

SELECT DTL_CD AS CD
     , DTL_NM AS CD_NM  
     , GRP_CD AS GRP_CD
  FROM JRBA_DTL_C
 WHERE USYN = 1



   AND RPT_GJDT = ( SELECT MAX(RPT_GJDT) AS RPT_GJDT
                      FROM JRBA_DTL_C
                  )


   AND RPT_GJDT = #{RPT_GJDT , jdbcType=VARCHAR}




	AND GRP_CD = #{GRP_CD, jdbcType=VARCHAR}


	AND HRNK_RBA_RSK_C = #{HRNK_RBA_RSK_C, jdbcType=VARCHAR}


	AND HRNK_RBA_RSK_C_V = #{HRNK_RBA_RSK_C_V, jdbcType=VARCHAR}

ORDER BY SNO

