UPDATE JRBA_RPT_RST_M 
   SET ATTCH_FILE_NO = 0
 WHERE RPT_GJDT = #{RPT_GJDT}

UPDATE RBA_ATTCH_FILE 
   SET DOWNLOAD_CNT = (DOWNLOAD_CNT + 1)
 WHERE 1 = 1
   AND ATTCH_FILE_NO = #{ATTCH_FILE_NO}
   AND FILE_SER      = #{FILE_SER}

	UPDATE JRBA_RPT_RST_M 
	   SET FIU_RPT_GJDT  = #{FIU_RPT_GJDT}
	     , ATTCH_FILE_NO = #{ATTCH_FILE_NO}
     WHERE RPT_GJDT = #{RPT_GJDT}

mapper.select:
	SELECT B.RPT_GJDT1 AS RPT_GJDT1
	     , IFNULL(( SELECT IN_V 
	               FROM JRBA_JIPYO_V 
	              WHERE RPT_GJDT=B.RPT_GJDT1 
	                AND JIPYO_IDX=#{JIPYO_IDX}
	           ),0) AS SCORE1
         , B.RPT_GJDT2 AS RPT_GJDT2                
         , IFNULL(( SELECT IN_V 
                   FROM JRBA_JIPYO_V 
                  WHERE RPT_GJDT=B.RPT_GJDT2 
                    AND JIPYO_IDX=#{JIPYO_IDX}
               ),0) AS SCORE2 
         , B.RPT_GJDT3 AS RPT_GJDT3           
         , IFNULL(( SELECT IN_V 
                   FROM JRBA_JIPYO_V 
                  WHERE RPT_GJDT=B.RPT_GJDT3 
                    AND JIPYO_IDX=#{JIPYO_IDX}
               ),0) AS SCORE3                       
      FROM JRBA_JIPYO_M A, 
                 ( SELECT MAX(CASE SNO WHEN 1 THEN BB.RPT_GJDT END ) AS RPT_GJDT1
	                      , MAX(CASE SNO WHEN 2 THEN BB.RPT_GJDT END ) AS RPT_GJDT2
	                      , MAX(CASE SNO WHEN 3 THEN BB.RPT_GJDT END ) AS RPT_GJDT3	                      
	                   FROM ( SELECT RPT_GJDT
	                               , @rownum := @rownum + 1  AS SNO
	                            FROM JRBA_RPT_BAS_M AA, (SELECT @rownum := 0) r  

	                           WHERE RPT_GJDT <= #{RPT_GJDT,jdbcType=VARCHAR}
	                           ORDER BY AA.RPT_GJDT DESC
	                        ) BB
	                  WHERE SNO < 4  

	)          B
     WHERE A.RPT_GJDT  = B.RPT_GJDT1          
       AND A.JIPYO_IDX = #{JIPYO_IDX}
     ORDER BY A.JIPYO_IDX

mapper.update:
           INSERT INTO JRBA_FIU_JIPYO_V 
	        (
	    RPT_GJDT
	    ,JIPYO_IDX
	    ,IN_V
	    ,RPT_PNT
	    ,ITEM_S_C
	    ,GRP_AVG_PNT
	    ,GRP_MAX_PNT
	    ,GRP_MIN_PNT
	    ,RANK
	    ,DR_DT
	    ,DR_TIME
	    ,DR_OP_JKW_NO
	    ,CHG_DT
	    ,CHG_TIME
	    ,CHG_OP_JKW_NO
		)
		VALUES
		(
	    #{RPT_GJDT, jdbcType=VARCHAR}
	    ,#{JIPYO_IDX, jdbcType=VARCHAR}
	    ,#{IN_V, jdbcType=VARCHAR}
	    ,#{RPT_PNT, jdbcType=VARCHAR}
	    ,#{ITEM_S_C, jdbcType=VARCHAR}
	    ,#{GRP_AVG_PNT, jdbcType=VARCHAR}    
  		,#{GRP_MAX_PNT, jdbcType=VARCHAR}    
  		,#{GRP_MIN_PNT, jdbcType=VARCHAR}
  		,#{RANK, jdbcType=VARCHAR}    
  	    ,DATE_FORMAT(SYSDATE(),'%Y%m%d')
	    ,DATE_FORMAT(SYSDATE(),'%H%i%s')
	    ,#{DR_OP_JKW_NO, jdbcType=VARCHAR}
	    ,DATE_FORMAT(SYSDATE(),'%Y%m%d')
	    ,DATE_FORMAT(SYSDATE(),'%H%i%s')
	    ,#{DR_OP_JKW_NO, jdbcType=VARCHAR}
		)
           ON DUPLICATE KEY 
            UPDATE
	       RPT_PNT  		= #{RPT_PNT, jdbcType=VARCHAR}
	       ,GRP_AVG_PNT  	= #{GRP_AVG_PNT, jdbcType=VARCHAR}
	       ,GRP_MAX_PNT  	= #{GRP_MAX_PNT, jdbcType=VARCHAR}
	       ,GRP_MIN_PNT  	= #{GRP_MIN_PNT, jdbcType=VARCHAR}
	       ,RANK  			= #{RANK, jdbcType=VARCHAR}
           ,CHG_DT 	 		= DATE_FORMAT(SYSDATE(),'%Y%m%d')
           ,CHG_TIME 		= DATE_FORMAT(SYSDATE(),'%H%i%s')
           ,CHG_OP_JKW_NO 	= #{DR_OP_JKW_NO, jdbcType=VARCHAR}
